INSERT INTO `weibo` VALUES (17, '中国妇女报', 'https://tvax4.sinaimg.cn/crop.0.0.600.600.180/9b57bbe2ly8hrz97ww3zdj20go0go3zg.jpg?KID=imgbed,tva&Expires=1728625501&ssig=nwEgTg203T', '5130.9万', 41747760, 6352418, 3209196, 'https://weibo.com/u/2606218210', 12654, 816, 704, '暂无地区信息', '【#陈丽君获中法传统文化交流大使称号#】10月10日18时，法国戴高乐机场1号航站楼，陈丽君受邀出席中法建交60周年 · 法中文化旅游年活动，现场向陈丽君颁发中法传统文化交流大使和巴黎机场热情好客大使的称号。（中国蓝新闻） http://t.cn/A6EQhDie ​', 'Fri Oct 11 09:17:16 +0800 2024', 'https://video.weibo.com/show?fid=1034:5088008953856030');
INSERT INTO `weibo` VALUES (18, '李肉肉日食记', 'https://tvax1.sinaimg.cn/crop.0.0.1080.1080.180/7df210f5ly8hkr6433l5gj20u00u0tao.jpg?KID=imgbed,tva&Expires=1728625501&ssig=pBtTbuKAMi', '528万', 3670336, 582718, 1027086, 'https://weibo.com/u/2113016053', 2532, 52, 30, '发布于 广东', '重阳节当然少不了美味小糕点啦~\n安排坚果饼干➕双层酥饼与家人分享吧🥰\n#美味话重阳##微博尝鲜计划##重阳赏秋记#http://t.cn/A6Vk5fXK ​', 'Fri Oct 11 09:24:30 +0800 2024', 'https://video.weibo.com/show?fid=1034:4646777840926748');
INSERT INTO `weibo` VALUES (19, '韩国me2day', 'https://tvax4.sinaimg.cn/crop.0.0.1080.1080.180/93f8d29dly8gdpvdh40a3j20u00u1juu.jpg?KID=imgbed,tva&Expires=1728625501&ssig=mAv7zD%2FmHJ', '20.68亿', 1674232954, 173259269, 220217530, 'https://weibo.com/u/2482557597', 3971, 540, 1542, '发布于 河南', '【Twi】RIIZE发布公告: 洪承汉将回归RIIZE，将依次参加11月计划的部分团队日程 #洪承汉[超话]# ​​​', 'Fri Oct 11 09:17:29 +0800 2024', '暂无视频');
