INSERT INTO `weibo` VALUES (21, '江苏卫视', 'https://tvax2.sinaimg.cn/crop.0.0.500.500.180/001ICKA4ly8hkskoxkr1bj60dw0dwt8w02.jpg?KID=imgbed,tva&Expires=1728625504&ssig=MQW1oACukd', '8518.9万', 59949688, 18075172, 7164632, 'https://weibo.com/u/1575527140', 4674, 565, 1029, '暂无地区信息', '#RED官宣音乐缘计划##音乐缘计划#赤色热情如火，音乐初心不改，@RED_OFFICIAL_ 已准备就绪！她们将以满腔的热忱和真挚的情感，用音符编织出一个个璀璨的瞬间。在即将到来的节目中，她们将带来怎样令人期待的作品？锁定@江苏卫视 &@爱奇艺 ，一起来感受她们舞台上的无限魅力！ ​', 'Fri Oct 11 09:03:29 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (22, '闪闪小小酥', 'https://tvax3.sinaimg.cn/crop.0.0.1080.1080.180/e944919cly8hjx1fcriolj20u00u0dhn.jpg?KID=imgbed,tva&Expires=1728625504&ssig=O2X0%2BFZRvn', '1638.6万', 2658920, 12916875, 809993, 'https://weibo.com/u/3913585052', 1126, 167, 483, '发布于 上海', '✨闪闪的探店日记✨\n📍小湘汇\n\n想了很久来长沙一定要打卡的餐厅！！没看到刘小策但是和长沙韩素希合了影🥹她人好好！！\n重点安利这道小刘楠！特别特别软糯的土豆牛腩，巨下饭👍底下还有鸡蛋，感觉是湘菜灵魂[二哈]还有据说之前是他们员工餐的牛蛙，因为员工觉得太好吃所以上了菜单，很辣但是好吃 ​', 'Fri Oct 11 09:30:18 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (23, '是张张的康康', 'https://tvax3.sinaimg.cn/crop.0.0.996.996.180/9f52cebdly8g4w2u5z8zkj20ro0rogvy.jpg?KID=imgbed,tva&Expires=1728625504&ssig=pFGafCMHRv', '171.4万', 1246088, 241019, 226616, 'https://weibo.com/u/2673004221', 856, 22, 527, '发布于 陕西', '一些湖州记忆[送花花]\n很典型的小桥流水人家宁静的江南小城，但因为旅游产业不如周边城市那么闻名于世，宁静这一点尤为突出。\n食物也很江南，凸出食材的鲜味为主。\n听说杭州人把这里当做后花园。有机会再去！\n #城市巡游记##带着微博探寻华夏##今日重阳愿您安康# ​', 'Fri Oct 11 09:26:09 +0800 2024', '暂无视频');
