INSERT INTO `weibo` VALUES (34, '人民日报', 'https://tvax4.sinaimg.cn/crop.0.0.1018.1018.180/0033ImPzly8h8vgemh8kxj60sa0sadgw02.jpg?KID=imgbed,tva&Expires=1728625504&ssig=fMPztcyv20', '36.20亿', 2317399234, 1049471386, 252899641, 'https://weibo.com/u/2803301701', 660, 249, 182, '暂无地区信息', '【#地磁暴对我们有何影响#？】#我国北部有机会出现极光# 国家空间天气监测预警中心预计，10日晚间到11日晚间，可能出现大地磁暴，如果没有新的爆发活动出现，12日可能会出现小到中等地磁暴，随后逐渐恢复平静。这对我们有什么影响？\n①简单说，它对人体的直接影响，基本感受不到。\n②对于正在进行秋赛 ​', 'Fri Oct 11 09:03:50 +0800 2024', '暂无视频');
