INSERT INTO `weibo` VALUES (45, '广东天姐', 'https://tvax3.sinaimg.cn/crop.0.0.838.838.180/006M2l05ly8hucsh9ah4kj30na0najsd.jpg?KID=imgbed,tva&Expires=1728625506&ssig=FK2C9RVtlp', '83.7万', 545525, 193221, 98741, 'https://weibo.com/u/6206618505', 625, 0, 0, '发布于 广东', '港股那边中芯国际最近表现挺猛的，节后回来带着一帮芯片股往上冲。在A股里头，值得投的芯片公司本来就不多，也就那几个头部企业有点看头。中芯国际现在可以说是芯片行业的风向标了，它要是能涨，其他芯片股跟着也能起飞；如果它不行了，大家估计都得趴下。\n跟台积电比起来，中芯国际确实还有不小的差距 ​', 'Fri Oct 11 09:13:44 +0800 2024', '暂无视频');
