INSERT INTO `weibo` VALUES (56, '芒果娱乐', 'https://tvax4.sinaimg.cn/crop.44.59.613.613.180/7077dc1dly8gdi6kcxpqnj20j60j63yt.jpg?KID=imgbed,tva&Expires=1728625506&ssig=ES1vBDe3UT', '4.38亿', 318058505, 64594084, 55229938, 'https://weibo.com/u/1886903325', 939, 136, 15, '暂无地区信息', '#SEVENTEEN官推更新# 战损玫瑰徐明浩爱了，破碎感拉满了🥺眼神好有戏，就这么一个眼神，能脑补出好多故事啊[抱一抱] ​', 'Fri Oct 11 09:26:50 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (57, '鍋盖頭司令', 'https://tvax3.sinaimg.cn/crop.0.0.1080.1080.180/002i5FJPly8hqesybtr91j60u00u0wgl02.jpg?KID=imgbed,tva&Expires=1728625506&ssig=%2F5LKDbguyd', '2603.8万', 19440323, 3470207, 3127810, 'https://weibo.com/u/2099591797', 398, 72, 19, '发布于 浙江', '#车主回应215万买到漏水迈巴赫#最近一直刷到哈哈哈，而且还有很多奔驰车主争相模仿[允悲]。\n我之前也是奔驰车主，买过一辆奔驰GLC，后来不到两年卖了[笑而不语]。原因嘛，刹车片噪音太大，之前的避震垫片嘎吱嘎吱响，开着不顺心，卖了。\n后来再换别时候，我只去看了揽胜和宝马X7，GLS和迈巴赫我都没试 ​', 'Fri Oct 11 09:11:47 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (58, '疯狂爱打板', 'https://tvax1.sinaimg.cn/crop.0.0.132.132.180/006IW9Joly8hr3y6nm3xij303o03omwz.jpg?KID=imgbed,tva&Expires=1728625506&ssig=WfE3FCSvRU', '646万', 6382151, 38780, 38958, 'https://weibo.com/u/6160816210', 427, 0, 0, '发布于 广东', '开盘前，请重点关注…\nA股已经进入第二阶段了，接下来是拼上市公司业绩的时候了…\n有机构已经帮我们统计出来了一份低估值，高增速的一份公司名单\n大部分集中在医药生物和基础化工两个行业，预计净利润增速都不低于40％\nA股还是有利于价值投资的，或许说价值投资适合A股的，如果说不适合那可能是我们对 ​', 'Fri Oct 11 09:53:35 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (59, '钮祜禄流流', 'https://tvax3.sinaimg.cn/crop.0.0.1080.1080.180/0067sxldly8hb5mhg94ljj30u00u0jtm.jpg?KID=imgbed,tva&Expires=1728625506&ssig=hddL4nUv0t', '3.43亿', 296492182, 18931256, 27185816, 'https://weibo.com/u/5607032695', 313, 146, 372, '发布于 四川', '#洪承汉归队#SM发布公告，洪承汉十一月归队 \nSM表示，“就今后团队的活动方向与成员们多次讨论，最终决定决定承汉重返团队”，“承汉加入组合，经过一定时间的准备后，将依次参加部分11月计划的团队行程。”\nRIIZE方面补充道：“为了让大家能看到七名成员组成的RIIZE，请相信我们的决定。”  ​', 'Fri Oct 11 09:06:55 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (60, '买家张俊', 'https://tvax2.sinaimg.cn/crop.0.0.1002.1002.180/9eaac76dly8gdik4zl7dsj20ru0rutch.jpg?KID=imgbed,tva&Expires=1728625506&ssig=KMDBO5Wh8J', '578.5万', 5013860, 237445, 533836, 'https://weibo.com/u/2661992301', 282, 60, 20, '发布于 湖北', '#听泉鉴宝宣布短暂停播# 都说听泉鉴宝是电子榨菜，这可不是白叫的！\n\n泉哥直播效果好，主要是他知识储备足，前一秒还在帮福布斯女富豪鉴宝，下一秒可能就跟盗墓贼连麦，在他直播间我看到了有些博物馆都没有的东西。\n\n听泉鉴宝近一个月涨粉千万，好像就是小杨哥带货香港美诚月饼出事的前后，不知道是不 ​', 'Fri Oct 11 09:32:37 +0800 2024', 'https://video.weibo.com/show?fid=1034:5088221034643497');
INSERT INTO `weibo` VALUES (61, 'Gemini郭家毅', 'https://tvax1.sinaimg.cn/crop.0.0.1080.1080.180/9b8d70d9ly8hsi5eni7rpj20u00u0gmv.jpg?KID=imgbed,tva&Expires=1728625509&ssig=OCu84%2BL%2Bpc', '1861.6万', 15743186, 347834, 2524508, 'https://weibo.com/u/2609737945', 542, 217, 9, '发布于 上海', '#郭家毅gemini[超话]##2024kpl年度总决赛# 今日预测！\n周五啦，周末要来咯！！ ​', 'Fri Oct 11 09:46:17 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (62, '北京卫视', 'https://tvax3.sinaimg.cn/crop.19.19.980.980.180/001Ws19Dly8guqvg2yufsj60rs0rs3z202.jpg?KID=imgbed,tva&Expires=1728625509&ssig=%2Buj9vYcPPK', '1.25亿', 84847178, 23563831, 16110730, 'https://weibo.com/u/1779837945', 1310, 175, 309, '暂无地区信息', '#伴肖战的歌声看阿勒泰河水双色奇观# 金秋时节，新疆苏木达依尔克河秋水盈盈，受地质因素影响，这条河的两条支流交汇处泾渭分明，一条犹如汉白玉带，另一条好似帝王绿带。伴着@X玖少年团肖战DAYTOY 的歌声，看这一道独特的景观！#我的祖国这么美# #带着微博去旅行# http://t.cn/A6EQ2fsJ ​', 'Fri Oct 11 09:30:00 +0800 2024', 'https://video.weibo.com/show?fid=1034:5087995876016171');
INSERT INTO `weibo` VALUES (63, '老鬼的瓜田', 'https://tvax4.sinaimg.cn/crop.0.0.995.995.180/50861ae8ly8gxx041rn6nj20rn0rngmc.jpg?KID=imgbed,tva&Expires=1728625509&ssig=6CGInQeHTQ', '1.79亿', 163641127, 6987973, 8497736, 'https://weibo.com/u/1350965992', 2214, 160, 139, '发布于 河南', 'S.M表示：经过工作人员和成员们的讨论，我们得出的结论是，从出道前开始就倾注心血计划的RIIZE，认为7名成员一起的时候会更有意义，所以我们将洪承汉归队。#SM确认洪承汉不退团# ​', 'Fri Oct 11 09:44:19 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (64, '演曼巴', 'https://tvax4.sinaimg.cn/crop.0.0.512.512.180/00634wlrly8hszgfm9f9qj30e80e8wf5.jpg?KID=imgbed,tva&Expires=1728625509&ssig=QthgbrFTNq', '1541.1万', 12619426, 167970, 2623788, 'https://weibo.com/u/5542203649', 285, 81, 1, '发布于 江苏', '老詹技术犯规，被打手裁判没吹。\n半场，雄鹿58-52湖人。 ​', 'Fri Oct 11 09:03:46 +0800 2024', '暂无视频');
