INSERT INTO `weibo` VALUES (66, '烫金真爱册', 'https://tvax2.sinaimg.cn/crop.0.0.1080.1080.180/0079UAaply8gxvo8joc7vj30u00u0jtq.jpg?KID=imgbed,tva&Expires=1728625509&ssig=lLfrfolgYv', '7237.3万', 52600967, 16848699, 2922957, 'https://weibo.com/u/6559402245', 1068, 67, 252, '发布于 湖南', '十分钟内好幽默的超绝反转 \n#洪承汉将11月回归RIIZE# ​', 'Fri Oct 11 09:20:06 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (67, '馋嘴番茄酱', 'https://tvax1.sinaimg.cn/crop.0.0.1080.1080.180/0071QmVuly8gdi6lvb2i9j30u00u0go7.jpg?KID=imgbed,tva&Expires=1728625509&ssig=m5SgpzZZOO', '3088.8万', 18494470, 7371415, 5022089, 'https://weibo.com/u/6440187348', 108, 105, 104, '发布于 北京', 'Share一下威海2日自驾路线🚗玩遍精华点\n终于去了心心念念的威海！！这次很幸运蹭到了朋友的车车🙈于是自驾环海玩了两天！！不得不说威海真的很适合开车玩，海岸线蛮长的而且公路也是沿着海岸线[爱慕]景色杠杠的！\n2天基本可以玩到所有精华点！嘻嘻，一整个大出片咯[ok]\nDay 1：悦海公园—威海公园 ​', 'Fri Oct 11 09:26:32 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (68, '圈内一把手', 'https://tvax2.sinaimg.cn/crop.0.0.737.737.180/7eb24ba3ly8fnyjik40g1j20kh0khjso.jpg?KID=imgbed,tva&Expires=1728625509&ssig=Lq8%2Bs5upCw', '8072万', 61229784, 9796466, 9693910, 'https://weibo.com/u/2125613987', 303, 202, 101, '发布于 安徽', '#锦绣安宁#这是什么宝藏古偶剧，接档长乐曲~剧粉的快乐又回来了。还是我会整活，锦上添“芒”，追剧更欢～全员“抱芒”，欢喜冤家甜爽逗乐！\n看预告剧情人设好带感！张晚意任敏饰演一对没有血缘的兄妹，十多年后重逢，为寻真相的两人开始靠近，命运之线有了交错，起底陈年冤案追寻真相，纷乱疑云中携手 ​', 'Fri Oct 11 09:48:05 +0800 2024', 'https://video.weibo.com/show?fid=1034:5088226684108879');
INSERT INTO `weibo` VALUES (69, '巨星研究社', 'https://tvax2.sinaimg.cn/crop.0.0.400.400.180/005KvKA1ly8giww5bwrxjj30b40b4jrn.jpg?KID=imgbed,tva&Expires=1728625509&ssig=LPpdz4NOuV', '6806.1万', 50149053, 8411677, 9500664, 'https://weibo.com/u/5267942841', 300, 202, 101, '发布于 安徽', '#宁静拍短剧#《开播短剧季》不仅汇聚了24位优秀的演员，还邀请了宁静、张萌、苏可三位实力派演员担任导师！从人气偶像到实力演员，从初出茅庐的新人到经验丰富的“老戏骨”，24位演员来自不同的领域，拥有不同的背景，但他们都怀揣着同一个梦想——在短剧的舞台上，绽放属于自己的光芒。\n以“敢说敢言 ​', 'Fri Oct 11 09:25:35 +0800 2024', 'https://video.weibo.com/show?fid=1034:5088221072392225');
