INSERT INTO `weibo` VALUES (91, 'A股一大将军', 'https://tvax1.sinaimg.cn/crop.0.0.360.360.180/881446b3ly8hbw0sam8ztj20a00a0jrd.jpg?KID=imgbed,tva&Expires=1728625513&ssig=f%2BbHmNLyV4', '276.8万', 2672256, 62155, 33675, 'https://weibo.com/u/2283030195', 235, 0, 0, '发布于 广东', '10月11日A股猛料：昨夜重磅！外盘突传大消息！倒车接人机会难得\n\n聚焦A股市场每日重磅消息！在阅读正文前，你必须知道一点：没有几个主力资金会笨到在利好一出炉就将股价直线拉升到涨停，所以请股民朋友们耐心一点，让利好飞一会，也许你会发现不一样的投资机会！\n\n　　【国内外财经要闻/A股大盘展望】 ​', 'Fri Oct 11 09:25:15 +0800 2024', '暂无视频');
