INSERT INTO `weibo` VALUES (98, '杭州校园', 'https://tvax4.sinaimg.cn/crop.0.0.663.663.180/77689455ly8h8v40jdesvj20if0ifdgj.jpg?KID=imgbed,tva&Expires=1728625513&ssig=n6WDFShiD3', '290.9万', 2283892, 328154, 297301, 'https://weibo.com/u/2003342421', 198, 21, 9, '暂无地区信息', '#在乌镇感受大型全景剧本杀#[爱慕]#来看浙江的高科技古镇# 乌镇，在古朴的表象之下，“黑科技”无孔不入。“乌镇全员NPC”，你在古镇看到的点点滴滴，都是一场场敬业的演出。但也别误会，这些“演员”中的许多人原本就是古镇的居民，“表演”的就是自己的生活！谁能拒绝这样的全景剧本杀呢～[坏笑] ​', 'Fri Oct 11 09:11:49 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (99, 'A股骑牛v', 'https://tvax2.sinaimg.cn/crop.0.0.1033.1033.180/0086VhPRly8hg3rpfuvloj30sp0spabh.jpg?KID=imgbed,tva&Expires=1728625513&ssig=1KHg005dlg', '156.2万', 1551122, 3945, 7330, 'https://weibo.com/u/7431373931', 271, 0, 0, '发布于 广东', '美国经济数据拉扯，美联储降息预期僵持！最新数据美国9月通胀数据超预期，降息货币宽松刺激通胀抬头；而9月就业数据大幅不及预期，指标创一年新高，劳动力市场疲软。\n\n相互矛盾的数据，美股表现是震荡，没有方向。\n\n之前预期美联储继续大幅降息，通胀抬头抑制加息预期；而就业数据不及预期衰退预期支持 ​', 'Fri Oct 11 09:01:55 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (100, '韩路', 'https://tvax1.sinaimg.cn/crop.875.148.530.530.180/471b3a04ly8gdx5xj7oo1j218x0u0agb.jpg?KID=imgbed,tva&Expires=1728625513&ssig=yJSiHTnon0', '2905.2万', 18602469, 3414008, 7035245, 'https://weibo.com/u/1192966660', 189, 146, 0, '发布于 北京', 'MEGA云南往回运路上，SU7郭弋搏借走了，新普拉多正从昆仑神宫往回运，剩下越野车也被同事借走十一出去玩都没还车呢。\n\n这俩，今天开哪个？ ​', 'Fri Oct 11 09:22:35 +0800 2024', '暂无视频');
