INSERT INTO `weibo` VALUES (104, '中国文娱网', 'https://tvax4.sinaimg.cn/crop.0.0.1242.1242.180/006WGyfnly8frk0ytjqhhj30yi0yitah.jpg?KID=imgbed,tva&Expires=1728625516&ssig=Db2o6Ke%2FcA', '310万', 1611162, 790142, 698480, 'https://weibo.com/u/6363965905', 130, 130, 260, '暂无地区信息', '#闲人填梦元白友谊具象化# 全新国风歌曲《闲人填梦》，歌唱家@邓超予Cherry 用自己的歌声将古人思念具像化，歌词中一句“唯梦闲人却难梦郎君”，源自于元稹写给白居易的诗“唯梦闲人不梦君”，轻松欢快的韵律中让人感受到的是思念的一丝哀愁。歌曲MV中#邓超予# 身穿一袭华服，由淡雅的青绿色勾勒出山水 ​', 'Fri Oct 11 09:24:19 +0800 2024', 'https://video.weibo.com/show?fid=1034:5087939948904497');
