INSERT INTO `weibo` VALUES (2050, '陌上蔷薇的瓜主日记', 'https://tvax2.sinaimg.cn/crop.0.0.512.512.180/95a9025dly8hkvuxcqi6fj20e80e8q3z.jpg?KID=imgbed,tva&Expires=1728626404&ssig=TGoMr2wChC', '444.8万', 3731802, 206414, 510074, 'https://weibo.com/u/2510881373', 254, 39, 16, '发布于 广西', '#莲花楼获金瞳奖最具口碑原创剧集#\n播完一年多的大爆剧成毅武侠莲花楼又拿奖啦👍\n最具口碑原创剧集🏆成毅《莲花楼》☝！\n最具商业价值成毅莲花楼IP联名银奖🏆☝\n2023年播完的剧又拿了2024金瞳奖，长尾效应长到天崩地裂海枯石烂，绝绝子👍！\n金瞳奖是业内最具权威性和影响力的奖项之一，含金量 ​', 'Fri Oct 11 10:03:33 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (2051, '新浪明星', 'https://tvax1.sinaimg.cn/crop.0.0.1080.1080.180/ae1ea3e4ly8h8v3pg8wfqj20u00u040x.jpg?KID=imgbed,tva&Expires=1728626404&ssig=RbILSH3bKY', '3340.2万', 23710595, 7719851, 1971816, 'https://weibo.com/u/2921243620', 203, 26, 16, '暂无地区信息', '#刘亦菲说给自己买保险很有想法# 刘亦菲以雨伞比喻保险，真的很精准！她认为保险在平时似乎不起眼，但在需要的时候就能发挥重要作用。为自己购买保险是一种体现责任感的行为，既是对未来的规划，也是在为家人守护。 ​', 'Fri Oct 11 10:04:13 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (2052, '我不叫周秋楠', 'https://tvax3.sinaimg.cn/crop.0.0.1080.1080.180/00622WALly8hrnzxxsdwhj30u00u0aco.jpg?KID=imgbed,tva&Expires=1728626404&ssig=o8L7voi512', '514.4万', 4645177, 187836, 310792, 'https://weibo.com/u/5527051551', 222, 3, 15, '发布于 山东', '什么都敢说什么都能讲，小s采访真有意思… http://t.cn/A6EQg6GR ​', 'Fri Oct 11 10:01:01 +0800 2024', 'https://video.weibo.com/show?fid=1034:5087875050438689');
INSERT INTO `weibo` VALUES (2053, '时尚星icon', 'https://tvax2.sinaimg.cn/crop.0.0.1021.1021.180/005C79Jbly8hu80ihuulrj30sd0sd0u8.jpg?KID=imgbed,tva&Expires=1728626404&ssig=5oh0zfIDNs', '2304.9万', 13978617, 5757864, 3312520, 'https://weibo.com/u/5143870621', 192, 32, 13, '发布于 北京', '#刘亦菲说给自己买保险很有想法# 刘亦菲在访谈中提到，保险就像雨伞，或许在晴天时看不出作用，但在风雨来袭时，它会给你最好的保护。她觉得给自己买保险是关心自己和家人的实际表现，非常有远见和责任感。 ​', 'Fri Oct 11 10:05:04 +0800 2024', '暂无视频');
