INSERT INTO `weibo` VALUES (3065, '新浪明星', 'https://tvax1.sinaimg.cn/crop.0.0.1080.1080.180/ae1ea3e4ly8h8v3pg8wfqj20u00u040x.jpg?KID=imgbed,tva&Expires=1728626639&ssig=BlOj%2Bk1cax', '3340.2万', 23710595, 7719851, 1971816, 'https://weibo.com/u/2921243620', 204, 27, 16, '暂无地区信息', '#刘亦菲说给自己买保险很有想法# 刘亦菲以雨伞比喻保险，真的很精准！她认为保险在平时似乎不起眼，但在需要的时候就能发挥重要作用。为自己购买保险是一种体现责任感的行为，既是对未来的规划，也是在为家人守护。 ​', 'Fri Oct 11 10:04:13 +0800 2024', '暂无视频');
