INSERT INTO `weibo` VALUES (4221, '陌上蔷薇的瓜主日记', 'https://tvax2.sinaimg.cn/crop.0.0.512.512.180/95a9025dly8hkvuxcqi6fj20e80e8q3z.jpg?KID=imgbed,tva&Expires=1728626904&ssig=aA5%2FKfqazf', '444.8万', 3731862, 206416, 510081, 'https://weibo.com/u/2510881373', 271, 40, 17, '发布于 广西', '#莲花楼获金瞳奖最具口碑原创剧集#\n播完一年多的大爆剧成毅武侠莲花楼又拿奖啦👍\n最具口碑原创剧集🏆成毅《莲花楼》☝！\n最具商业价值成毅莲花楼IP联名银奖🏆☝\n2023年播完的剧又拿了2024金瞳奖，长尾效应长到天崩地裂海枯石烂，绝绝子👍！\n金瞳奖是业内最具权威性和影响力的奖项之一，含金量 ​', 'Fri Oct 11 10:03:33 +0800 2024', '暂无视频');
INSERT INTO `weibo` VALUES (4222, '新浪明星', 'https://tvax1.sinaimg.cn/crop.0.0.1080.1080.180/ae1ea3e4ly8h8v3pg8wfqj20u00u040x.jpg?KID=imgbed,tva&Expires=1728626904&ssig=8HKAnpChBo', '3340.2万', 23710595, 7719851, 1971816, 'https://weibo.com/u/2921243620', 206, 27, 16, '暂无地区信息', '#刘亦菲说给自己买保险很有想法# 刘亦菲以雨伞比喻保险，真的很精准！她认为保险在平时似乎不起眼，但在需要的时候就能发挥重要作用。为自己购买保险是一种体现责任感的行为，既是对未来的规划，也是在为家人守护。 ​', 'Fri Oct 11 10:04:13 +0800 2024', '暂无视频');
