INSERT INTO `weibo` VALUES (4468, '陌上蔷薇的瓜主日记', 'https://tvax2.sinaimg.cn/crop.0.0.512.512.180/95a9025dly8hkvuxcqi6fj20e80e8q3z.jpg?KID=imgbed,tva&Expires=1728626963&ssig=4owFC335WW', '444.8万', 3731865, 206417, 510081, 'https://weibo.com/u/2510881373', 272, 40, 18, '发布于 广西', '#莲花楼获金瞳奖最具口碑原创剧集#\n播完一年多的大爆剧成毅武侠莲花楼又拿奖啦👍\n最具口碑原创剧集🏆成毅《莲花楼》☝！\n最具商业价值成毅莲花楼IP联名银奖🏆☝\n2023年播完的剧又拿了2024金瞳奖，长尾效应长到天崩地裂海枯石烂，绝绝子👍！\n金瞳奖是业内最具权威性和影响力的奖项之一，含金量 ​', 'Fri Oct 11 10:03:33 +0800 2024', '暂无视频');
